/**
 * @summary Get documents accessible via a QR code (public or authenticated)
 */
export const getGetQrContentUrl = (token: string) => {
  return `/api/qr/${token}`;
};

export const getQrContent = async (
  token: string,
  options?: RequestInit,
): Promise<QrContent> => {
  return customFetch<QrContent>(getGetQrContentUrl(token), {
    ...options,
    method: "GET",
  });
};

export const getGetQrContentQueryKey = (token: string) => {
  return [`/api/qr/${token}`] as const;
};

export const getGetQrContentQueryOptions = <
  TData = Awaited<ReturnType<typeof getQrContent>>,
  TError = ErrorType<unknown>,
>(
  token: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getQrContent>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetQrContentQueryKey(token);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getQrContent>>> = ({
    signal,
  }) => getQrContent(token, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!token,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getQrContent>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetQrContentQueryResult = NonNullable<
  Awaited<ReturnType<typeof getQrContent>>
>;
export type GetQrContentQueryError = ErrorType<unknown>;

/**
 * @summary Get documents accessible via a QR code (public or authenticated)
 */

export function useGetQrContent<
  TData = Awaited<ReturnType<typeof getQrContent>>,
  TError = ErrorType<unknown>,
>(
  token: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getQrContent>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetQrContentQueryOptions(token, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
